// ServerInterface represents all server handlers.
type ServerInterface interface {
	// Campaigns the current user belongs to
	// (GET /campaigns)
	ListCampaigns(w http.ResponseWriter, r *http.Request)
	// Create a campaign (caller becomes its DM)
	// (POST /campaigns)
	CreateCampaign(w http.ResponseWriter, r *http.Request)
	// Join a campaign as a player using its invite code
	// (POST /campaigns/join)
	JoinCampaign(w http.ResponseWriter, r *http.Request)
	// Players barred from rejoining this campaign (DM only)
	// (GET /campaigns/{campaignId}/bans)
	ListBans(w http.ResponseWriter, r *http.Request, campaignId CampaignId)
	// Bar a user from this campaign (DM only). If currently a member they are kicked first; the invite code no longer admits them until unbanned.
	// (POST /campaigns/{campaignId}/bans)
	BanMember(w http.ResponseWriter, r *http.Request, campaignId CampaignId)
	// Lift a ban so the invite code admits them again (DM only)
	// (DELETE /campaigns/{campaignId}/bans/{userId})
	UnbanMember(w http.ResponseWriter, r *http.Request, campaignId CampaignId, userId UserId)
	// The party's field journal (members). DM sees full records; players see only unveiled sections.
	// (GET /campaigns/{campaignId}/bestiary)
	ListBestiary(w http.ResponseWriter, r *http.Request, campaignId CampaignId)
	// Log a new sighting (any member)
	// (POST /campaigns/{campaignId}/bestiary)
	CreateBestiaryEntry(w http.ResponseWriter, r *http.Request, campaignId CampaignId)
	// Remove a sighting and its notes (creator/DM)
	// (DELETE /campaigns/{campaignId}/bestiary/{entryId})
	DeleteBestiaryEntry(w http.ResponseWriter, r *http.Request, campaignId CampaignId, entryId openapi_types.UUID)
	// Rename a sighting (creator/DM), or identify and unveil it (DM only)
	// (PATCH /campaigns/{campaignId}/bestiary/{entryId})
	UpdateBestiaryEntry(w http.ResponseWriter, r *http.Request, campaignId CampaignId, entryId openapi_types.UUID)
	// Pen a field note on a sighting (any member)
	// (POST /campaigns/{campaignId}/bestiary/{entryId}/notes)
	AddBestiaryNote(w http.ResponseWriter, r *http.Request, campaignId CampaignId, entryId openapi_types.UUID)
	// Erase a field note (its author, or the DM)
	// (DELETE /campaigns/{campaignId}/bestiary/{entryId}/notes/{noteId})
	DeleteBestiaryNote(w http.ResponseWriter, r *http.Request, campaignId CampaignId, entryId openapi_types.UUID, noteId openapi_types.UUID)
	// The campaign's party roster (members only)
	// (GET /campaigns/{campaignId}/characters)
	ListCharacters(w http.ResponseWriter, r *http.Request, campaignId CampaignId)
	// Add a character owned by the caller (any campaign member)
	// (POST /campaigns/{campaignId}/characters)
	CreateCharacter(w http.ResponseWriter, r *http.Request, campaignId CampaignId)
	// The campaign's codex — every explicit ruling plus proposals (members)
	// (GET /campaigns/{campaignId}/codex)
	GetCodex(w http.ResponseWriter, r *http.Request, campaignId CampaignId)
	// Offer your homebrew to the table (members; DM decides)
	// (POST /campaigns/{campaignId}/codex)
	ProposeCodexContent(w http.ResponseWriter, r *http.Request, campaignId CampaignId)
	// One verdict over many entries (DM only — pack admissions)
	// (POST /campaigns/{campaignId}/codex/bulk)
	SetCodexStatusBulk(w http.ResponseWriter, r *http.Request, campaignId CampaignId)
	// Remove a ruling — back to defaults (DM only)
	// (DELETE /campaigns/{campaignId}/codex/{contentId})
	ClearCodexStatus(w http.ResponseWriter, r *http.Request, campaignId CampaignId, contentId openapi_types.UUID)
	// The DM's verdict on an entry (enable homebrew, ban/unban SRD)
	// (PUT /campaigns/{campaignId}/codex/{contentId})
	SetCodexStatus(w http.ResponseWriter, r *http.Request, campaignId CampaignId, contentId openapi_types.UUID)
	// The DM's encounter library — drafts, the active one, and past ones (DM only)
	// (GET /campaigns/{campaignId}/encounters)
	ListEncounters(w http.ResponseWriter, r *http.Request, campaignId CampaignId)
	// Prepare a new (draft) encounter (DM only)
	// (POST /campaigns/{campaignId}/encounters)
	CreateEncounter(w http.ResponseWriter, r *http.Request, campaignId CampaignId)
	// The running encounter (members) — redacted for players. 204 when none is active.
	// (GET /campaigns/{campaignId}/encounters/active)
	GetActiveEncounter(w http.ResponseWriter, r *http.Request, campaignId CampaignId)
	// The campaign chronicle, newest first (members)
	// (GET /campaigns/{campaignId}/events)
	ListEvents(w http.ResponseWriter, r *http.Request, campaignId CampaignId, params ListEventsParams)
	// Write an entry into the chronicle (any member; players post to player chat)
	// (POST /campaigns/{campaignId}/events)
	AddChronicleNote(w http.ResponseWriter, r *http.Request, campaignId CampaignId)
	// The campaign atlas — every map, no image bytes (members)
	// (GET /campaigns/{campaignId}/maps)
	ListMaps(w http.ResponseWriter, r *http.Request, campaignId CampaignId)
	// Hang a new map in the atlas (DM only)
	// (POST /campaigns/{campaignId}/maps)
	CreateMap(w http.ResponseWriter, r *http.Request, campaignId CampaignId)
	// Set or clear the table's level ceiling (DM only)
	// (PUT /campaigns/{campaignId}/max-level)
	SetMaxLevel(w http.ResponseWriter, r *http.Request, campaignId CampaignId)
	// Everyone seated at the table (members only)
	// (GET /campaigns/{campaignId}/members)
	ListMembers(w http.ResponseWriter, r *http.Request, campaignId CampaignId)
	// Remove a player from the table (DM only). Their heroes return to My Heroes, their claims on open quests are released, and they leave any knowledge pools. They may rejoin with the invite code unless banned.
	// (DELETE /campaigns/{campaignId}/members/{userId})
	KickMember(w http.ResponseWriter, r *http.Request, campaignId CampaignId, userId UserId)
	// A milestone — every seated hero gains one pending level-up (DM only)
	// (POST /campaigns/{campaignId}/milestone)
	DeclareMilestone(w http.ResponseWriter, r *http.Request, campaignId CampaignId)
	// Set or clear when the table gathers next (DM only)
	// (PUT /campaigns/{campaignId}/next-session)
	SetNextSession(w http.ResponseWriter, r *http.Request, campaignId CampaignId)
	// Switch the campaign between milestone and XP progression (DM only)
	// (PUT /campaigns/{campaignId}/progression)
	SetProgression(w http.ResponseWriter, r *http.Request, campaignId CampaignId)
	// List quests on a campaign's board (members only)
	// (GET /campaigns/{campaignId}/quests)
	ListQuests(w http.ResponseWriter, r *http.Request, campaignId CampaignId)
	// Post a new quest (DM only)
	// (POST /campaigns/{campaignId}/quests)
	CreateQuest(w http.ResponseWriter, r *http.Request, campaignId CampaignId)
	// Generate a fresh invite code (DM only)
	// (POST /campaigns/{campaignId}/regenerate-invite)
	RegenerateInvite(w http.ResponseWriter, r *http.Request, campaignId CampaignId)
	// The campaign's skill trees (members only)
	// (GET /campaigns/{campaignId}/trees)
	ListTrees(w http.ResponseWriter, r *http.Request, campaignId CampaignId)
	// Create a skill tree (DM only)
	// (POST /campaigns/{campaignId}/trees)
	CreateTree(w http.ResponseWriter, r *http.Request, campaignId CampaignId)
	// Grant (or dock) XP to seated heroes (DM only)
	// (POST /campaigns/{campaignId}/xp)
	GrantXP(w http.ResponseWriter, r *http.Request, campaignId CampaignId)
	// Remove a character (its owner or the DM)
	// (DELETE /characters/{characterId})
	DeleteCharacter(w http.ResponseWriter, r *http.Request, characterId CharacterId)
	// A hero's full sheet — owner, or members of the seated campaign
	// (GET /characters/{characterId})
	GetCharacter(w http.ResponseWriter, r *http.Request, characterId CharacterId)
	// Update a character (its owner or the DM)
	// (PATCH /characters/{characterId})
	UpdateCharacter(w http.ResponseWriter, r *http.Request, characterId CharacterId)
	// Add an item to a hero's inventory (owner or DM)
	// (POST /characters/{characterId}/items)
	AddInventoryItem(w http.ResponseWriter, r *http.Request, characterId CharacterId)
	// Remove an inventory row (owner or DM)
	// (DELETE /characters/{characterId}/items/{itemId})
	DeleteInventoryItem(w http.ResponseWriter, r *http.Request, characterId CharacterId, itemId openapi_types.UUID)
	// Change quantity or equip state (owner or DM)
	// (PATCH /characters/{characterId}/items/{itemId})
	UpdateInventoryItem(w http.ResponseWriter, r *http.Request, characterId CharacterId, itemId openapi_types.UUID)
	// Advance a forged hero one level (owner only)
	// (POST /characters/{characterId}/levelup)
	LevelUpCharacter(w http.ResponseWriter, r *http.Request, characterId CharacterId)
	// Seat a hero at a campaign, or null to return them to My Heroes (owner only)
	// (PUT /characters/{characterId}/seat)
	SeatCharacter(w http.ResponseWriter, r *http.Request, characterId CharacterId)
	// Set spell slots spent (owner or DM; casters only)
	// (PUT /characters/{characterId}/slots)
	SetSpellSlots(w http.ResponseWriter, r *http.Request, characterId CharacterId)
	// A character's pact and web progress (members only)
	// (GET /characters/{characterId}/tree)
	GetCharacterTree(w http.ResponseWriter, r *http.Request, characterId CharacterId)
	// Bind a character to a tree — the pact (DM only)
	// (PUT /characters/{characterId}/tree)
	SetCharacterTree(w http.ResponseWriter, r *http.Request, characterId CharacterId)
	// Grant unspent picks at a story beat (DM only)
	// (POST /characters/{characterId}/tree/grants)
	GrantPicks(w http.ResponseWriter, r *http.Request, characterId CharacterId)
	// Spend a granted pick on a reachable node (owner or DM)
	// (POST /characters/{characterId}/tree/picks)
	SpendPick(w http.ResponseWriter, r *http.Request, characterId CharacterId)
	// Remove a combatant (DM only)
	// (DELETE /combatants/{combatantId})
	DeleteCombatant(w http.ResponseWriter, r *http.Request, combatantId CombatantId)
	// Edit a combatant — HP, initiative, reveal, rename (DM only)
	// (PATCH /combatants/{combatantId})
	UpdateCombatant(w http.ResponseWriter, r *http.Request, combatantId CombatantId)
	// Roll this combatant's initiative (DM, or the owner of a PC combatant)
	// (POST /combatants/{combatantId}/roll)
	RollCombatantInitiative(w http.ResponseWriter, r *http.Request, combatantId CombatantId)
	// Discard an encounter and its combatants (DM only)
	// (DELETE /encounters/{encounterId})
	DeleteEncounter(w http.ResponseWriter, r *http.Request, encounterId EncounterId)
	// One encounter with its combatants — full detail (DM only)
	// (GET /encounters/{encounterId})
	GetEncounter(w http.ResponseWriter, r *http.Request, encounterId EncounterId)
	// Rename, trigger/end, or advance the tracker (DM only)
	// (PATCH /encounters/{encounterId})
	UpdateEncounter(w http.ResponseWriter, r *http.Request, encounterId EncounterId)
	// Add a Den monster, a seated PC, or a custom line (DM only)
	// (POST /encounters/{encounterId}/combatants)
	AddCombatant(w http.ResponseWriter, r *http.Request, encounterId EncounterId)
	// Roll initiative (d20 + modifier) for every combatant at once (DM only)
	// (POST /encounters/{encounterId}/roll-initiative)
	RollInitiative(w http.ResponseWriter, r *http.Request, encounterId EncounterId)
	// Liveness / readiness probe
	// (GET /health)
	GetHealth(w http.ResponseWriter, r *http.Request)
	// Strike a map and all its pins (DM only)
	// (DELETE /maps/{mapId})
	DeleteMap(w http.ResponseWriter, r *http.Request, mapId MapId)
	// One map with its pins (members; players never receive DM-only pins)
	// (GET /maps/{mapId})
	GetMap(w http.ResponseWriter, r *http.Request, mapId MapId)
	// Rename a map or re-hang it under a parent (DM only)
	// (PATCH /maps/{mapId})
	UpdateMap(w http.ResponseWriter, r *http.Request, mapId MapId)
	// Drop a pin on the map (DM only)
	// (POST /maps/{mapId}/pins)
	CreateMapPin(w http.ResponseWriter, r *http.Request, mapId MapId)
	// The reveal ledger — every submitted batch on this map (DM only)
	// (GET /maps/{mapId}/reveals)
	ListReveals(w http.ResponseWriter, r *http.Request, mapId MapId)
	// Lift the fog — commit a draft of stamped circles as one batch (DM only)
	// (POST /maps/{mapId}/reveals)
	SubmitReveals(w http.ResponseWriter, r *http.Request, mapId MapId)
	// The currently authenticated user and their campaign memberships
	// (GET /me)
	GetCurrentUser(w http.ResponseWriter, r *http.Request)
	// The caller's heroes across all campaigns, including unseated ones
	// (GET /me/characters)
	ListMyCharacters(w http.ResponseWriter, r *http.Request)
	// Forge a hero in My Heroes (not seated at any campaign)
	// (POST /me/characters)
	CreateMyCharacter(w http.ResponseWriter, r *http.Request)
	// Create a hero through the builder — full sheet, derived HP
	// (POST /me/characters/forge)
	ForgeCharacter(w http.ResponseWriter, r *http.Request)
	// Remove a power node (DM only)
	// (DELETE /nodes/{nodeId})
	DeleteNode(w http.ResponseWriter, r *http.Request, nodeId NodeId)
	// Update a power node (DM only)
	// (PATCH /nodes/{nodeId})
	UpdateNode(w http.ResponseWriter, r *http.Request, nodeId NodeId)
	// Pull a pin off the map (DM only)
	// (DELETE /pins/{pinId})
	DeleteMapPin(w http.ResponseWriter, r *http.Request, pinId PinId)
	// Move or reword a pin (DM only)
	// (PATCH /pins/{pinId})
	UpdateMapPin(w http.ResponseWriter, r *http.Request, pinId PinId)
	// Remove a quest (DM only)
	// (DELETE /quests/{questId})
	DeleteQuest(w http.ResponseWriter, r *http.Request, questId QuestId)
	// Update a quest, including its status and rewards (DM only)
	// (PATCH /quests/{questId})
	UpdateQuest(w http.ResponseWriter, r *http.Request, questId QuestId)
	// Release a previously claimed quest
	// (DELETE /quests/{questId}/claim)
	UnclaimQuest(w http.ResponseWriter, r *http.Request, questId QuestId)
	// Claim a quest (any campaign member)
	// (POST /quests/{questId}/claim)
	ClaimQuest(w http.ResponseWriter, r *http.Request, questId QuestId)
	// Tear a batch out of the ledger — its area fogs over again (DM only)
	// (DELETE /reveals/{batchId})
	DeleteReveals(w http.ResponseWriter, r *http.Request, batchId openapi_types.UUID)
	// Remove a homebrew entry (author only)
	// (DELETE /rules/content/{contentId})
	DeleteRulesContent(w http.ResponseWriter, r *http.Request, contentId openapi_types.UUID)
	// Edit a homebrew entry (author only; SRD is immutable)
	// (PUT /rules/content/{contentId})
	UpdateRulesContent(w http.ResponseWriter, r *http.Request, contentId openapi_types.UUID)
	// Your homebrew as a content pack (keep it out of public repos)
	// (GET /rules/export)
	ExportContentPack(w http.ResponseWriter, r *http.Request)
	// Delete your homebrew — all of it, one kind, or one book (author's own only)
	// (DELETE /rules/homebrew)
	ResetHomebrew(w http.ResponseWriter, r *http.Request, params ResetHomebrewParams)
	// Your homebrew grouped by source book — the imported-packs shelf
	// (GET /rules/homebrew/books)
	GetHomebrewBooks(w http.ResponseWriter, r *http.Request)
	// What a homebrew reset would touch — counts and in-use references
	// (GET /rules/homebrew/impact)
	GetHomebrewImpact(w http.ResponseWriter, r *http.Request)
	// Batch-import a content pack as your private homebrew (upserts by name)
	// (POST /rules/import)
	ImportContentPack(w http.ResponseWriter, r *http.Request)
	// Rules content of one kind (SRD + this instance's homebrew)
	// (GET /rules/{kind})
	ListRules(w http.ResponseWriter, r *http.Request, kind ContentKind)
	// Add a homebrew entry of this kind (any signed-in user)
	// (POST /rules/{kind})
	CreateRulesContent(w http.ResponseWriter, r *http.Request, kind ContentKind)
	// Delete a skill tree and its web (DM only)
	// (DELETE /trees/{treeId})
	DeleteTree(w http.ResponseWriter, r *http.Request, treeId TreeId)
	// A skill tree with its full web (members only)
	// (GET /trees/{treeId})
	GetTree(w http.ResponseWriter, r *http.Request, treeId TreeId)
	// Update a skill tree (DM only)
	// (PATCH /trees/{treeId})
	UpdateTree(w http.ResponseWriter, r *http.Request, treeId TreeId)
	// Replace the tree's web of connections (DM only)
	// (PUT /trees/{treeId}/edges)
	SetEdges(w http.ResponseWriter, r *http.Request, treeId TreeId)
	// Add a power node to a tree (DM only)
	// (POST /trees/{treeId}/nodes)
	CreateNode(w http.ResponseWriter, r *http.Request, treeId TreeId)
}

